import { useState, useRef, useEffect } from "react";

import MainBtns from "../../Components/Buttons/MainBtns";
import InputForm from "../../Components/Input/InputForm";

function ProfilePage() {

  const [text, setText] = useState("");
  const textareaRef = useRef(null);

  useEffect(() => {
    const textarea = textareaRef.current;
    textarea.style.height = "auto";
    textarea.style.height = textarea.scrollHeight + "px";
  }, [text]);


  return (
    <div style={{flex:1, display:"flex", flexDirection:"column", alignItems:"center"}}>
      <header style={{display:"flex",flexDirection:"column", borderBottom:"1px solid #ccc", alignItems:"center", justifyContent:"center"}}>
        <h2 style={{fontWeight:"500"}}>Profile</h2>
        <span style={{marginBottom:"1rem", fontWeight:"100"}}>Add info about yourself</span>
      </header>
      <div style={{flex:1,marginInline:"auto", minWidth:"500px"}}>
        <div className="Basics" style={{display:"flex", flexDirection:"column", marginTop:"1.5rem" }}>
          <span>Basics:</span>
          <InputForm TextPlaceholder={"Name"} styles={"mini-input"}/>
          <InputForm TextPlaceholder={"LastName"} styles={"mini-input"}/>
          <InputForm TextPlaceholder={"Role"} styles={"mini-input"}/>
        </div>
        <div className="Biografy" style={{display:"flex", flexDirection:"column", marginTop:"1.5rem" }}>
          <span>Biografy:</span>
          <textarea className="text-area"  placeholder="Biografy" onChange={(e) => setText(e.target.value)}/>
        </div>
      </div>
      <div style={{width:"100%", display:"flex", justifyContent:"center"}}>
        <MainBtns Style={"purple-btn"} Text={"Save"} Width={"30%"}/>
      </div>
    </div>
  );
}

export default ProfilePage;
